// Merge all input items into a single object
const merged = $input.all().reduce((acc, item) => {
  return { ...acc, ...item.json };
}, {});

return [{ json: merged }];

const text = $json.message;

const match = text.match(
  /TID:([A-Z0-9]+).*?Received\s+Ksh\s*([\d,.]+)\s+from\s+(.+?)\s+(\d{9,15})\s+on\s+(\d{2}\/\d{2}\/\d{2})\s+([\d:]+\s+(?:AM|PM))/i
);

if (!match) return {};

return {
  json: {
    provider: 'airtel',
    reference: match[1],
    amount: Number(match[2].replace(/,/g, '')),
    payer: match[3].trim(),
    phone: match[4],
    groupId: $json.from, 
    date: match[5],
    time: match[6]
  }
};

const text = $json.message;

const match = text.match(
  /^([A-Z0-9]+)\s+Confirmed.*?received\s+Ksh([\d,.]+)\s+from\s+(.+?)\s+(\d{9,12})\s+on\s+(\d{1,2}\/\d{1,2}\/\d{2})\s+at\s+([\d:]+\s+(?:AM|PM))/i
);

if (!match) return {};

return {
  json: {
    provider: 'mpesa',
    reference: match[1],
    amount: Number(match[2].replace(/,/g, '')),
    payer: match[3].trim(),
    phone: match[4],
    groupId: $json.from, 
    date: match[5],
    time: match[6]
  }
};

const message = ($json.message || $json.chatInput || '').trim();
const sessionId = $json.sessionId;
const from = $json.from || sessionId;
const to = $json.to || 'unknown';

let paymentType = 'unknown';

const closeCampaign = [
  "close",
  "restart",
  "refresh",
  "delete",
  "end"
   ];

const summaryKeywords = [
  "summary",
  "total",
  "progress"
   ];

const text = message.toLowerCase();

if (summaryKeywords.some(keyword => text.includes(keyword))) {
  paymentType = 'summary';
  }

else if (closeCampaign.some(keyword => text.includes(keyword))) {
  paymentType = 'clean';
  }
/**
 * AIRTEL MONEY
 * Example:
 * TID:D3IFW8CJ4D4. Received Ksh 1 from Duli...
 */
else if (/^TID:[A-Z0-9]+/i.test(message)) {
  paymentType = 'airtel';
  }

/**
 * M-PESA
 * Example:
 * UAUGD53S37 Confirmed. You have received Ksh1...
 */
else if (/^[A-Z0-9]+\s+Confirmed\b/i.test(message)) {
  paymentType = 'mpesa';
  }

return { json: { paymentType, message, from, to, sessionId} };

