  ]
;

// Filter out items that don't have a proper .json.amount
const validItems = items.filter(item => item.json && typeof item.json.amount === 'number');

if (validItems.length === 0) {
  return [
    { json: { message: "No payments yet. Paste each MPESA message after receiving payment. Scramble sensitive details" } }
  ];
}

let total = 0;
let lines = [];

items.forEach((item, index) => {
  const row = item.json;

  // Defensive checks
  if (typeof row.amount !== 'number') return;

  total += row.amount;
  lines.push(`${index + 1}. ${row.payer} – Ksh ${row.amount}`);
});

return [
  {
    json: {
      message:
          `💰 Payment Summary \n
           ${lines.join('\n')}
           *Total: Ksh ${total}*`
           }
   }
  ]
;

